const telegramId = $('Telegram Trigger').item.json.message.from.id;
const chatId = $('Telegram Trigger').item.json.message.chat.id;
const userMessage = $('Telegram Trigger').item.json.message.text || '';
const sessionResults = $('Check Active Session').all();

let route, sessionId, existingMessages, repId;

if (sessionResults.length > 0 && sessionResults[0].json && sessionResults[0].json.id) {
  // Active session exists → continue conversation
  route = 'continue';
  sessionId = sessionResults[0].json.id;
  repId = sessionResults[0].json.rep_id;
  existingMessages = sessionResults[0].json.messages || [];
} else if (userMessage.trim() === '/story') {
  // No session + /story command → start new
  route = 'new_story';
  sessionId = null;
  existingMessages = [];
} else {
  // No session + other message → ignore silently
  route = 'ignore';
}

return [{json: {route, telegramId, chatId, userMessage, sessionId, existingMessages, repId}}];

const repResults = $('Check Rep').all();
const data = $('Route Logic').item.json;

if (!repResults.length || !repResults[0].json || !repResults[0].json.id) {
  return [{json: {...data, valid: false, reason: 'not_registered'}}];
}

const rep = repResults[0].json;

if (!rep.manifesto_accepted) {
  return [{json: {...data, valid: false, reason: 'manifesto_pending', repId: rep.id}}];
}

if (rep.credits <= 0) {
  return [{json: {...data, valid: false, reason: 'no_credits', repId: rep.id}}];
}

return [{json: {...data, valid: true, repId: rep.id, repName: rep.name}}];

// Get data — works for both continue and new_story paths
// Try to get from Validate Rep node first, fall back to Route Logic
let data;
try {
  data = $('Validate Rep').item.json;
} catch(e) {
  data = $('Route Logic').item.json;
}

const { telegramId, chatId, userMessage, sessionId, existingMessages, repId } = data;

// Build messages array
let messages = Array.isArray(existingMessages) ? [...existingMessages] : [];

// Add user message (first message triggers welcome)
const messageContent = messages.length === 0 ? 'START_STORY_SESSION' : userMessage;
messages.push({role: 'user', content: messageContent});

return [{json: {
  telegramId,
  chatId,
  userMessage,
  sessionId,
  repId,
  messages,
  isNewSession: sessionId === null
}}];

const claudeResponse = $('Call Claude').item.json;
const buildData = $('Build Messages').item.json;

// Extract text from Claude response
let claudeText = '';
if (claudeResponse.content && claudeResponse.content.length > 0) {
  claudeText = claudeResponse.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('');
}

// Check for [POST_READY] signal
const isComplete = claudeText.includes('[POST_READY]');

// Clean the text to send to user (remove the tag)
const cleanText = claudeText.replace('[POST_READY]', '').trim();

// Build updated messages array (append Claude's response)
const updatedMessages = [...buildData.messages, {
  role: 'assistant',
  content: claudeText  // Store full text including tag in DB
}];

// Extract story content if complete (everything before [POST_READY])
const storyContent = isComplete ? cleanText : null;

return [{json: {
  claudeText: cleanText,
  isComplete,
  storyContent,
  updatedMessages,
  sessionId: buildData.sessionId,
  repId: buildData.repId,
  chatId: buildData.chatId,
  telegramId: buildData.telegramId,
  isNewSession: buildData.isNewSession
}}];

const data = $('Parse Claude Response').item.json;
const method = data.isNewSession ? 'POST' : 'PATCH';
const url = data.isNewSession
  ? 'YOUR_SUPABASE_URL/rest/v1/sessions'
  : `YOUR_SUPABASE_URL/rest/v1/sessions?id=eq.${data.sessionId}`;

// Build body based on method (PATCH omits rep_id and telegram_id)
const body = method === 'POST'
  ? {
      rep_id: data.repId,
      telegram_id: data.telegramId,
      messages: data.updatedMessages,
      status: data.isComplete ? 'complete' : 'in_progress',
      updated_at: new Date().toISOString()
    }
  : {
      messages: data.updatedMessages,
      status: data.isComplete ? 'complete' : 'in_progress',
      updated_at: new Date().toISOString()
    };

return [{json: {
  ...data,
  supabaseMethod: method,
  supabaseUrl: url,
  sessionBody: body
}}];
